parameters.jsCode:
const text = $input.item.json.output?.[1]?.content?.[0]?.text || "";

// Extract score
const scoreMatch = text.match(/Score:\s*(\d+)/i);

// Extract summary
const summaryMatch = text.match(/Summary:\s*([\s\S]*)/i);

return [
  {
    json: {
      aiScore: scoreMatch ? parseInt(scoreMatch[1]) : 0,
      aiSummary: summaryMatch ? summaryMatch[1].trim() : "No summary",
      fullText: text
    }
  }
];
